#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int X, Y;
        scanf("%d %d", &X, &Y);
        int chaats = X / 2;
        if (chaats > Y) chaats = Y;
        printf("%d\n", chaats);
    }
    return 0;
}

